#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        int answer = -1;
        for (int i = 0; i < N; ++i) {
            long long x;
            scanf("%lld", &x);
            if (answer == -1 && x == 8) answer = i;
        }
        printf("%d\n", answer);
    }
    return 0;
}

