import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        ans = -1
        for i in range(N):
            val = int(next(it))
            if ans == -1 and val == 8:
                ans = i
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

